1	<script lang="ts">
2		// DotMeter v2, the judge's hand-built take, for direct iteration with Jake.
3		// The design thesis: multiply-and-add should be VISIBLE, not narrated.
4		// Every bar is literally its two products stacked; the strip below shows
5		// the arithmetic for whichever candidate you select, live, to two decimals.
6	
7		// The two entries mean something: x is how loud, y is how fast.
8		const CANDIDATES = [
9			{ id: 'c1', name: 'c1', angle: 20 },
10			{ id: 'c2', name: 'c2', angle: 70 },
11			{ id: 'c3', name: 'c3', angle: 110 },
12			{ id: 'c4', name: 'c4', angle: 160 }
13		];
14	
15		let challenge = $state<null | 'cheat' | 'short'>(null);
16		let solvedCheat = $state(false);
17		let solvedShort = $state(false);
18		const WHY = {
19			cheat:
20				"A candidate that is simply bigger everywhere piles up score without matching the probe's direction. A raw dot product overrates large vectors, so a system built on it keeps preferring whatever is biggest.",
21			short:
22				"A small candidate that matches the probe exactly gets buried under bigger ones. Size is drowning direction, and fixing that is exactly where this lesson is headed."
23		};
24		function startChallenge(kind: 'cheat' | 'short') {
25			// one click always re-arms: a solved card resets on first click,
26			// whether or not another challenge was active in between
27			if (kind === 'cheat' && (challenge === 'cheat' || solvedCheat)) solvedCheat = false;
28			if (kind === 'short' && (challenge === 'short' || solvedShort)) solvedShort = false;
29			challenge = kind;
30			probeAngle = 40;
31			lengthC1 = 1.0;
32			selected = 'c1';
33		}
34		$effect(() => {
35			if (challenge === 'cheat' && cheatActive) solvedCheat = true;
36			if (challenge === 'short' && shortChanged) solvedShort = true;
37		});
38	
39		let probeAngle = $state(40);
40		let lengthC1 = $state(1.0);
41		let selected = $state('c1');
42		let hovered = $state<string | null>(null);
43		let dragging = $state<'probe' | 'length' | null>(null);
44	
45		const rad = (d: number) => (d * Math.PI) / 180;
46	
47		const probe = $derived({ x: Math.cos(rad(probeAngle)), y: Math.sin(rad(probeAngle)) });
48	
49		const rows = $derived(
50			CANDIDATES.map((c) => {
51				const len = c.id === 'c1' ? lengthC1 : 1;
52				const x = len * Math.cos(rad(c.angle));
53				const y = len * Math.sin(rad(c.angle));
54				const px = probe.x * x; // the x-term product
55				const py = probe.y * y; // the y-term product
56				return { ...c, len, x, y, px, py, score: px + py };
57			})
58		);
59	
60		const maxScore = $derived(Math.max(...rows.map((r) => r.score)));
61		const leaders = $derived(rows.filter((r) => Math.abs(r.score - maxScore) < 0.005).map((r) => r.id));
62		const tied = $derived(leaders.length > 1);
63		const sel = $derived(rows.find((r) => r.id === selected) ?? rows[0]);
64	
65		// The mirror lesson: c1 aims truest but is too short to win.
66		const shortChanged = $derived.by(() => {
67			const c1 = rows[0];
68			if (lengthC1 >= 0.95 || leaders.includes('c1')) return false;
69			return rows.every(
70				(r) =>
71					r.id === 'c1' ||
72					Math.abs(((r.angle - probeAngle + 540) % 360) - 180) >
73						Math.abs(((c1.angle - probeAngle + 540) % 360) - 180)
74			);
75		});
76	
77		// The overtake: c1 stretched AND outscoring a candidate that out-aligns it.
78		// Returns the most deserving victim (best-aligned beaten song) so the flag
79		// can name the exact pair instead of making a vague claim about the board.
80		const cheatVictim = $derived.by(() => {
81			const c1 = rows[0];
82			if (lengthC1 <= 1.05) return null;
83			const dist = (angle: number) => Math.abs(((angle - probeAngle + 540) % 360) - 180);
84			const beaten = rows.filter(
85				(r) => r.id !== 'c1' && dist(r.angle) < dist(c1.angle) && c1.score > r.score + 0.005
86			);
87			if (beaten.length === 0) return null;
88			return beaten.reduce((a, b) => (dist(a.angle) < dist(b.angle) ? a : b));
89		});
90		const cheatActive = $derived(cheatVictim !== null);
91		const leaderName = $derived(rows.find((r) => r.id === leaders[0])?.name ?? '');
92	
93		// --- Arena geometry (SVG units) ---
94		const S = 400; // viewBox square
95		const CX = S / 2;
96		const CY = S / 2;
97		const R = 92; // unit arrow length in px; 2.0 x R stays inside the frame
98		const pt = (x: number, y: number) => ({ px: CX + x * R, py: CY - y * R });
99	
100		function arrow(x: number, y: number) {
101			const tip = pt(x, y);
102			const ang = Math.atan2(CY - tip.py, tip.px - CX);
103			const L = Math.hypot(tip.px - CX, tip.py - CY);
104			const head = Math.max(7, Math.min(11, L * 0.09));
105			const back = { px: tip.px - head * Math.cos(ang), py: tip.py + head * Math.sin(ang) };
106			const left = {
107				px: back.px - head * 0.55 * Math.sin(ang),
108				py: back.py - head * 0.55 * Math.cos(ang)
109			};
110			const right = {
111				px: back.px + head * 0.55 * Math.sin(ang),
112				py: back.py + head * 0.55 * Math.cos(ang)
113			};
114			return {
115				shaft: { x1: CX, y1: CY, x2: back.px, y2: back.py },
116				head: `${tip.px},${tip.py} ${left.px},${left.py} ${right.px},${right.py}`
117			};
118		}
119	
120		function labelPos(angle: number, len: number, pad = 20, tangentDeg = 0) {
121			const d = len * R + pad;
122			const a = angle + tangentDeg;
123			return { px: CX + d * Math.cos(rad(a)), py: CY - d * Math.sin(rad(a)) };
124		}
125	
126		let arenaEl = $state<SVGSVGElement | null>(null);
127	
128		function anglesFromEvent(e: PointerEvent) {
129			if (!arenaEl) return null;
130			const r = arenaEl.getBoundingClientRect();
131			const x = ((e.clientX - r.left) / r.width) * S - CX;
132			const y = CY - ((e.clientY - r.top) / r.height) * S;
133			return { angle: ((Math.atan2(y, x) * 180) / Math.PI + 360) % 360, dist: Math.hypot(x, y) / R };
134		}
135	
136		function onArenaPointer(e: PointerEvent) {
137			const a = anglesFromEvent(e);
138			if (!a || !dragging) return;
139			if (dragging === 'probe') probeAngle = Math.round(a.angle / 5) * 5 % 360;
140			else lengthC1 = Math.max(0.5, Math.min(2, Math.round(a.dist * 10) / 10));
141		}
142	
143		function startDrag(kind: 'probe' | 'length', e: PointerEvent) {
144			dragging = kind;
145			(e.currentTarget as Element).setPointerCapture(e.pointerId);
146		}
147	
148		function probeKeys(e: KeyboardEvent) {
149			let h = true;
150			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = (probeAngle + 5) % 360;
151			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = (probeAngle + 355) % 360;
152			else h = false;
153			if (h) e.preventDefault();
154		}
155	
156		function lengthKeys(e: KeyboardEvent) {
157			let h = true;
158			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
159			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
160			else h = false;
161			if (h) e.preventDefault();
162		}
163	
164		const f = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(2);
165		const cl = (v: number) => Math.min(Math.max(v, 24), S - 24);
166		const f1 = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(1);
167	
168		// Bar scale: scores live in [-2, 2] once c1 can stretch.
169		const BARMAX = 2.05;
170		const barH = 96;
171		const segH = (v: number) => (Math.abs(v) / BARMAX) * (barH / 2);
172	
173		const probeTip = $derived(pt(probe.x, probe.y));
174		const c1row = $derived(rows[0]);
175		const c1HandlePos = $derived(pt(c1row.x, c1row.y));
176	</script>
177	
178	<svelte:window onpointerup={() => (dragging = null)} />
179	
180	<div class="lab" data-interactive="dot-alignment">
181		<p class="invite">
182			Turn the probe or drag c1's round handle: watch every score rise, fall, or flip sign, live.
183		</p>
184		<div class="challenges">
185			<button class="chal" class:active={challenge === 'cheat' && !solvedCheat} class:done={solvedCheat} onclick={() => startChallenge('cheat')}>
186				<span class="chal-t mono">challenge 01</span>
187				<span class="chal-g">Make a worse match win</span>
188				{#if solvedCheat}
189					<span class="chal-s mono">✓ solved · click to retry</span>
190					<span class="chal-why">{WHY.cheat}</span>
191				{:else if challenge === 'cheat'}
192					<span class="chal-s mono live">in play…</span>
193				{/if}
194			</button>
195			<button class="chal" class:active={challenge === 'short' && !solvedShort} class:done={solvedShort} onclick={() => startChallenge('short')}>
196				<span class="chal-t mono">challenge 02</span>
197				<span class="chal-g">Make the truest match lose</span>
198				{#if solvedShort}
199					<span class="chal-s mono">✓ solved · click to retry</span>
200					<span class="chal-why">{WHY.short}</span>
201				{:else if challenge === 'short'}
202					<span class="chal-s mono live">in play…</span>
203				{/if}
204			</button>
205		</div>
206	
207		<div class="stage">
208			<div class="arena-wrap">
209				<svg
210					bind:this={arenaEl}
211					viewBox="0 0 {S} {S}"
212					class="arena"
213					onpointermove={onArenaPointer}
214					role="img"
215					aria-label="An amber probe arrow among four periwinkle candidate arrows; drag the probe tip to turn it, drag c1's tip to stretch it"
216				>
217					<!-- angle ring + ticks -->
218					<circle cx={CX} cy={CY} r={R} class="ring" />
219					{#each Array.from({ length: 12 }, (_, i) => i * 30) as t (t)}
220						<line
221							x1={CX + (R - 4) * Math.cos(rad(t))}
222							y1={CY - (R - 4) * Math.sin(rad(t))}
223							x2={CX + (R + 4) * Math.cos(rad(t))}
224							y2={CY - (R + 4) * Math.sin(rad(t))}
225							class="tick"
226						/>
227					{/each}
228					<!-- axes, whisper-quiet, but named: the two entries ARE qualities -->
229					<line x1={CX - R - 14} y1={CY} x2={CX + R + 14} y2={CY} class="axis" />
230					<line x1={CX} y1={CY - R - 14} x2={CX} y2={CY + R + 14} class="axis" />
231					<text x={CX + R + 18} y={CY - 6} class="axisq q-loud mono" aria-hidden="true">loud</text>
232					<text x={CX - 10} y={CY - R - 8} text-anchor="end" class="axisq q-fast mono" aria-hidden="true">fast</text>
233	
234					<!-- coordinates made visible: dashed drops for probe and selected -->
235					{#each [{ x: probe.x, y: probe.y, cls: 'p' }, { x: sel.x, y: sel.y, cls: 'c' }] as d (d.cls)}
236						{@const tip = pt(d.x, d.y)}
237						<line x1={tip.px} y1={tip.py} x2={tip.px} y2={CY} class="drop {d.cls}" />
238						<line x1={tip.px} y1={tip.py} x2={CX} y2={tip.py} class="drop {d.cls}" />
239						<text x={cl(tip.px)} y={CY + (d.cls === 'p' ? 13 : 25)} class="coord mono {d.cls}" aria-hidden="true">{f(d.x)}</text>
240						<text x={CX - (d.cls === 'p' ? 4 : 32)} y={cl(tip.py) - 3} class="coord mono {d.cls}" text-anchor="end" aria-hidden="true">{f(d.y)}</text>
241					{/each}
242	
243					<!-- candidates -->
244					{#each rows as r (r.id)}
245						{@const a = arrow(r.x, r.y)}
246						<g
247							class="cand"
248							class:sel={selected === r.id}
249							class:hov={hovered === r.id}
250							onpointerdown={() => (selected = r.id)}
251							role="button"
252							tabindex="-1"
253							aria-label={`select ${r.name}`}
254						>
255							<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft cand-stroke" />
256							<polygon points={a.head} class="cand-fill" />
257							{@const lp = labelPos(r.angle, r.len, 26)}
258							<text
259								x={Math.min(Math.max(lp.px, 44), S - 48)}
260								y={Math.min(Math.max(lp.py, 16), S - 10)}
261								class="lab song-lab halo"
262								class:sel-lab={selected === r.id}
263								aria-hidden="true">{r.name}</text>
264						</g>
265					{/each}
266	
267					<!-- c1 length handle -->
268					<circle
269						cx={c1HandlePos.px}
270						cy={c1HandlePos.py}
271						r="32"
272						onpointermove={onArenaPointer}
273						class="handle length-handle"
274						class:active={dragging === 'length'}
275						class:pulse={challenge !== null && !((challenge === 'cheat' && cheatActive) || (challenge === 'short' && shortChanged))}
276						onpointerdown={(e) => startDrag('length', e)}
277						onkeydown={lengthKeys}
278						role="slider"
279						tabindex="0"
280						data-control="length-c1"
281						aria-label="c1 length"
282						aria-valuemin="0.5"
283						aria-valuemax="2"
284						aria-valuenow={f1(lengthC1)}
285					/>
286	
287					<!-- probe on top -->
288					{#if true}
289						{@const a = arrow(probe.x, probe.y)}
290						<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft probe-stroke" />
291						<polygon points={a.head} class="probe-fill" />
292					{/if}
293					{@const plp = labelPos(probeAngle, 1, 30, 16)}
294					<text
295						x={Math.min(Math.max(plp.px, 44), S - 48)}
