316				</svg>
317			</div>
318	
319			<div class="meter">
320				{#each rows as r (r.id)}
321					<button
322						class="row"
323						class:leading={leaders.includes(r.id) && !tied}
324						class:sel={selected === r.id}
325						onmouseenter={() => (hovered = r.id)}
326						onmouseleave={() => (hovered = null)}
327						onclick={() => (selected = r.id)}
328						aria-label={`${r.name} score ${f1(r.score)}${leaders.includes(r.id) && !tied ? ', leading' : ''}`}
329					>
330						<span class="row-id">{r.name}</span>
331						<span class="bar" style="--h: {barH}px">
332							<span class="zero"></span>
333							<!-- x-term segment then y-term segment, stacked from the baseline -->
334							<span
335								class="seg segx"
336								class:neg={r.px < 0}
337								style="height: {segH(r.px)}px; bottom: {r.px >= 0 ? barH / 2 : barH / 2 - segH(r.px)}px"
338							></span>
339							<span
340								class="seg segy"
341								class:neg={r.py < 0}
342								style="height: {segH(r.py)}px; bottom: {r.py >= 0
343									? barH / 2 + (r.px > 0 ? segH(r.px) : 0)
344									: barH / 2 - segH(r.py) - (r.px < 0 ? segH(r.px) : 0)}px"
345							></span>
346						</span>
347						<span class="row-score mono" class:neg={r.score < 0}>{f1(r.score)}</span>
348						{#if leaders.includes(r.id) && !tied}<span class="leads mono">leads</span>{/if}
349					</button>
350				{/each}
351				{#if tied}<span class="tie mono">tied</span>{/if}
352				{#if cheatVictim}
353					<span class="flag mono">⚑ {cheatVictim.name} matches the probe better, but {c1row.name} outscores it on size</span>
354				{:else if shortChanged}
